import type Graphic from "../../Graphic.js";
import type FormTemplate from "../../form/FormTemplate.js";
import type FeatureLayer from "../../layers/FeatureLayer.js";
import type GeoJSONLayer from "../../layers/GeoJSONLayer.js";
import type OrientedImageryLayer from "../../layers/OrientedImageryLayer.js";
import type SceneLayer from "../../layers/SceneLayer.js";
import type KnowledgeGraphSublayer from "../../layers/knowledgeGraph/KnowledgeGraphSublayer.js";
import type SubtypeSublayer from "../../layers/support/SubtypeSublayer.js";
import type { FieldValue } from "../../layers/support/fieldUtils.js";

/**
 * The current state of the BatchAttributeForm.
 *
 * @since 5.0
 */
export type BatchAttributeFormState = "not-loaded" | "loading" | "failed" | "loaded";

/**
 * The mode of the form.
 *
 * @since 5.0
 */
export type BatchAttributeFormMode = "single" | "batch";

/**
 * An array of layers included in the [BatchAttributeForm](https://developers.arcgis.com/javascript/latest/references/core/widgets/BatchAttributeForm/). Each layer must support feature editing and field access.
 *
 * @since 5.0
 */
export type AttributeFormSupportedLayerUnion = FeatureLayer | GeoJSONLayer | OrientedImageryLayer | SceneLayer | SubtypeSublayer | KnowledgeGraphSublayer;

/**
 * Describes the state of a single feature's attribute values at the time of a form submission.
 *
 * @since 5.0
 */
export interface SubmitResult {
  /**
   * The feature described by this result object.
   *
   * @since 5.0
   */
  feature: Graphic;
  /**
   * The names of fields that have invalid values for this feature.
   *
   * @since 5.0
   */
  invalidFields: string[];
  /**
   * The updated attribute values for the feature.
   *
   * @since 5.0
   */
  values: Graphic["attributes"];
}

/** @since 5.0 */
export interface SubmitEvent {
  /**
   * The name of the event.
   *
   * @since 5.0
   */
  name: "submit";
  /**
   * An array containing a result object for each feature in the form.
   *
   * @since 5.0
   */
  results: SubmitResult[];
  /**
   * Indicates whether the form is valid. This is `true` if all features in the form have valid attribute values, and `false` if any feature has at least one invalid attribute value.
   *
   * @since 5.0
   */
  valid: boolean;
}

/** @since 5.0 */
export interface ValueChangeEvent {
  /**
   * The features affected by the value change.
   *
   * @since 5.0
   */
  features: Graphic[];
  /**
   * The name of the field that was changed.
   *
   * @since 5.0
   */
  fieldName: string;
  /**
   * The name of the event.
   *
   * @since 5.0
   */
  name: "value-change";
  /**
   * The updated field value.
   *
   * @since 5.0
   */
  value: FieldValue;
}

/**
 * Configurations used for setting the layer's [FormTemplate](https://developers.arcgis.com/javascript/latest/references/core/form/FormTemplate/) within `BatchAttributeForm`.
 *
 * @since 5.0
 */
export interface AttributeFormSupportedLayerInfo {
  /**
   * The associated layer containing the fields to edit.
   *
   * @since 5.0
   */
  layer: AttributeFormSupportedLayerUnion;
  /**
   * A template that defines the feature's form content. Use this when setting the fields for editing.
   *
   * @since 5.0
   */
  formTemplate?: FormTemplate;
}